  1→import { useEffect, useRef } from 'react';
  2→
  3→export interface KeyCombo {
  4→  key: string;
  5→  meta?: boolean;
  6→  ctrl?: boolean;
  7→  alt?: boolean;
  8→  shift?: boolean;
  9→}
 10→
 11→export interface ShortcutOptions {
 12→  enabled?: boolean;
 13→  preventDefault?: boolean;
 14→}
 15→
 16→type ComboKey = string;
 17→
 18→function comboToKey(combo: KeyCombo): ComboKey {
 19→  const parts: string[] = [];
 20→  if (combo.meta) parts.push('meta');
 21→  if (combo.ctrl) parts.push('ctrl');
 22→  if (combo.alt) parts.push('alt');
 23→  if (combo.shift) parts.push('shift');
 24→  parts.push(combo.key.toLowerCase());
 25→  return parts.join('+');
 26→}
 27→
 28→const activeShortcuts = new Map<ComboKey, number>();
 29→
 30→function registerCombo(combo: KeyCombo): ComboKey {
 31→  const key = comboToKey(combo);
 32→  const count = activeShortcuts.get(key) ?? 0;
 33→  if (import.meta.env.DEV && count > 0) {
 34→    console.warn(
 35→      `[useKeyboardShortcut] Duplicate shortcut registered: ${key}. ` +
 36→        `The most recently mounted handler will take precedence.`,
 37→    );
 38→  }
 39→  activeShortcuts.set(key, count + 1);
 40→  return key;
 41→}
 42→
 43→function unregisterCombo(key: ComboKey) {
 44→  const count = activeShortcuts.get(key) ?? 0;
 45→  if (count <= 1) {
 46→    activeShortcuts.delete(key);
 47→  } else {
 48→    activeShortcuts.set(key, count - 1);
 49→  }
 50→}
 51→
 52→function matchesCombo(e: KeyboardEvent, combo: KeyCombo): boolean {
 53→  if (e.key.toLowerCase() !== combo.key.toLowerCase()) return false;
 54→  if (!!combo.meta !== e.metaKey) return false;
 55→  if (!!combo.ctrl !== e.ctrlKey) return false;
 56→  if (!!combo.alt !== e.altKey) return false;
 57→  if (!!combo.shift !== e.shiftKey) return false;
 58→  return true;
 59→}
 60→
 61→export function useKeyboardShortcut(
 62→  combo: KeyCombo,
 63→  handler: () => void,
 64→  options?: ShortcutOptions,
 65→): void {
 66→  const handlerRef = useRef(handler);
 67→  handlerRef.current = handler;
 68→
 69→  const enabled = options?.enabled ?? true;
 70→  const preventDefault = options?.preventDefault ?? true;
 71→
 72→  useEffect(() => {
 73→    if (!enabled) return;
 74→
 75→    const comboKey = registerCombo(combo);
 76→
 77→    function handleKeyDown(e: KeyboardEvent) {
 78→      if (matchesCombo(e, combo)) {
 79→        if (preventDefault) {
 80→          e.preventDefault();
 81→        }
 82→        handlerRef.current();
 83→      }
 84→    }
 85→
 86→    window.addEventListener('keydown', handleKeyDown);
 87→    return () => {
 88→      window.removeEventListener('keydown', handleKeyDown);
 89→      unregisterCombo(comboKey);
 90→    };
 91→  }, [
 92→    combo.key,
 93→    combo.meta,
 94→    combo.ctrl,
 95→    combo.alt,
 96→    combo.shift,
 97→    enabled,
 98→    preventDefault,
 99→  ]);
100→}
